// Custom

hook — useFetch
function

useFetch(url) {
const

[data, setData] = useState(null);
const

[loading, setLoading] = useState(true);
const

[error, setError] = useState(null);
useEffect(() => {
setLoading(true);
fetch(url)
.then(res

=> res.json())
.then(d => { setData(d); setLoading(false);

})
.catch(e

=> { setError(e); setLoading(false);

});
}, [url]);
return {

data, loading, error };
}
// Use karo kisi bhi component mein
const

{ data, loading, error } = useFetch('/api/users');

